        self.color = color
        self.is_king = False

    def __str__(self):
        return 'K' if self.is_king else self.color[0].upper()
```

### Step 3: Game Class

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def get_opponent(self):
        return 'b' if self.current_player == 'r' else 'r'

    def is_valid_move(self, from_pos, to_pos):
        row_from, col_from = map(int, from_pos.split(','))
        row_to, col_to = map(int, to_pos.split(','))

        piece = self.board.board[row_from][col_from]
        if not piece:
            return False

        if piece[0] != self.current_player:
            return False

        # Check valid move for regular pieces
        if row_to == row_from + 1 and abs(col_to - col_from) == 1:
            return True

        # Check valid capture move for regular pieces
        if (abs(row_to - row_from) == 2 and abs(col_to - col_from) == 2 and 
                self.board.board[(row_from + row_to) // 2][(col_from + col_to) // 2]):
            return True

        # Check valid king move
        if piece[0].lower() == 'k':
            if row_to == row_from + 1 or row_to == row_from - 1 and abs(col_to - col_from) == 1:
                return True

        return False

    def make_move(self, from_pos, to_pos):
        row_from, col_from = map(int, from_pos.split(','))
        row_to, col_to = map(int, to_pos.split(','))

        piece = self.board.board[row_from][col_from]
        if not self.is_valid_move(from_pos, to_pos):
            return False

        self.board.board[row_to][col_to] = piece
        self.board.board[row_from][col_from] = ''

        # Check for capture and update king status
        if abs(row_to - row_from) == 2:
            captured_row = (row_to + row_from) // 2
            captured_col = (col_to + col_from) // 2
            self.board.board[captured_row][captured_col] = ''

        # Check for kinging
        if self.current_player == 'r' and row_to == 7 or self.current_player == 'b' and row_to == 0:
            piece.is_king = True

        self.current_player = self.get_opponent()
        return True

    def check_winner(self):
        pieces = [piece for row in self.board.board for piece in row if piece]
        if not any(piece.color == 'r' for piece in pieces) or all(piece.is_king for piece in pieces):
            return 'b'
        elif not any(piece.color == 'b' for piece in pieces) or all(piece.is_king for piece in pieces):
            return 'r'
        return None
```

