    game = Game()
    game.board.print_board()

    while True:
        from_pos = input(f"{game.current_player}'s turn. Enter move (from-to): ")
        if not from_pos:
            print("Invalid move. Please try again.")
            continue

        to_pos = input("Enter destination: ")
        if not to_pos:
            print("Invalid move. Please try again.")
            continue

        if game.make_move(from_pos, to_pos):
            game.board.print_board()
            winner = game.check_winner()
            if winner:
                print(f"{winner} wins!")
                break
        else:
            print("Invalid move. Please try again.")

if __name__ == "__main__":
    main()
